module alu #(
    parameter ADD = 6'b100000,
    parameter ADDU = 6'b100001,
    parameter SUB = 6'b100010,
    parameter SUBU = 6'b100011,
    parameter AND = 6'b100100,
    parameter OR = 6'b100101,
    parameter XOR = 6'b100110,
    parameter NOR = 6'b100111,
    parameter SLT = 6'b101010,
    parameter SLTU = 6'b101011,
    parameter SLL = 6'b000000,
    parameter SRL = 6'b000010,
    parameter SRA = 6'b000011,
    parameter SLLV = 6'b000100,
    parameter SRLV = 6'b000110,
    parameter SRAV = 6'b000111,
    parameter LUI = 6'b001111
) (
    input [31:0] a,
    input [31:0] b,
    input [5:0] aluc,
    output reg [31:0] r,
    output zero,
    output reg carry,
    output negative,
    output reg overflow,
    output reg flag
);
reg [32:0] res;
reg [5:0] shamt;
assign zero = (res[31:0] == 32'b0);
assign negative = res[31];
always @(*) begin
    carry = 0;
    overflow = 0;
    flag = 0;
    case (aluc)
        ADD: {carry, res} = {1'b0, a} + {1'b0, b};
        ADDU: res = a + b;
        SUB: {carry, res} = {1'b0, a} - {1'b0, b};
        SUBU: res = a - b;
        AND: res = a & b;
        OR: res = a | b;
        XOR: res = a ^ b;
        NOR: res = ~(a | b);
        SLT: begin
            res = ($signed(a) < $signed(b)) ? 32'b1 : 32'b0;
            flag = res[0];
        end
        SLTU: begin
            res = (a < b) ? 32'b1 : 32'b0;
            flag = res[0];
        end
        SLL: shamt = b[4:0];
        SRL: shamt = b[4:0];
        SRA: shamt = b[4:0];
        SLLV: shamt = a[4:0];
        SRLV: shamt = a[4:0];
        SRAV: shamt = a[4:0];
        LUI: res = {b[15:0], 16'b0};
        default: res = 33'b0;
    endcase
    r = res[31:0];
end
endmodule
